import React, { useState } from 'react';
import { Link, useNavigate, useLocation } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { AlertTriangle, LogOut, Plus, LayoutDashboard, Shield, Menu, X } from 'lucide-react';

export default function Navbar() {
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const location = useLocation();
  const [open, setOpen] = useState(false);

  const handleLogout = () => { logout(); navigate('/'); };
  const active = (path) => location.pathname === path;

  return (
    <nav style={{
      background: 'rgba(10,12,15,0.95)',
      backdropFilter: 'blur(12px)',
      borderBottom: '1px solid var(--border)',
      position: 'sticky', top: 0, zIndex: 100
    }}>
      <div style={{ maxWidth:1200, margin:'0 auto', padding:'0 24px', display:'flex', alignItems:'center', justifyContent:'space-between', height:60 }}>

        <Link to="/" style={{ display:'flex', alignItems:'center', gap:8 }}>
          <div style={{ background:'var(--accent)', borderRadius:8, padding:'6px 8px', display:'flex' }}>
            <AlertTriangle size={18} color="#fff" strokeWidth={2.5}/>
          </div>
          <span style={{ fontFamily:'var(--font-display)', fontWeight:800, fontSize:18 }}>
            Road<span style={{ color:'var(--accent)' }}>Alert</span>
          </span>
        </Link>

        <div style={{ display:'flex', alignItems:'center', gap:8 }}>
          {user?.role === 'civilian' && <>
            <NavLink to="/dashboard" active={active('/dashboard')} icon={<LayoutDashboard size={15}/>}>Dashboard</NavLink>
            <NavLink to="/submit"    active={active('/submit')}    icon={<Plus size={15}/>}>Report</NavLink>
          </>}
          {user?.role === 'authority' &&
            <NavLink to="/authority" active={active('/authority')} icon={<Shield size={15}/>}>Authority Panel</NavLink>
          }
          <div style={{ width:1, height:24, background:'var(--border)', margin:'0 8px' }}/>
          {user ? (
            <div style={{ display:'flex', alignItems:'center', gap:10 }}>
              <div>
                <div style={{ fontSize:13, fontWeight:600 }}>{user.name}</div>
                <div style={{ fontSize:11, color: user.role==='authority' ? 'var(--accent)' : 'var(--text-muted)', textTransform:'capitalize' }}>{user.role}</div>
              </div>
              <button className="btn btn-ghost btn-sm" onClick={handleLogout}>
                <LogOut size={14}/> Logout
              </button>
            </div>
          ) : (
            <div style={{ display:'flex', gap:8 }}>
              <Link to="/login"    className="btn btn-ghost btn-sm">Login</Link>
              <Link to="/register" className="btn btn-primary btn-sm">Sign Up</Link>
            </div>
          )}
        </div>
      </div>
    </nav>
  );
}

function NavLink({ to, active, icon, children }) {
  return (
    <Link to={to} style={{
      display:'inline-flex', alignItems:'center', gap:6,
      padding:'6px 12px', borderRadius:8, fontSize:14, fontWeight:500,
      color: active ? 'var(--accent)' : 'var(--text-muted)',
      background: active ? 'var(--accent-glow)' : 'transparent',
      transition:'all 0.15s'
    }}>
      {icon}{children}
    </Link>
  );
}
